from typing import List
from itertools import permutations

class Solution:
    def minTransfers(self, transactions: List[List[int]]) -> int:
        # Calculate the balance for each person
        balance = {}
        for frm, to, amt in transactions:
            balance[frm] = balance.get(frm, 0) - amt
            balance[to] = balance.get(to, 0) + amt

        # Filter out people with zero balance
        debtors = [amt for amt in balance.values() if amt != 0]

        # Try all permutations to find the minimum number of transactions
        min_transactions = float('inf')
        for perm in permutations(debtors):
            count = 0
            for i in range(len(perm)):
                if perm[i] != 0:
                    for j in range(i + 1, len(perm)):
                        if perm[j] != 0:
                            perm[i] += perm[j]
                            perm[j] = 0
                            count += 1
                            break
            min_transactions = min(min_transactions, count)

        return min_transactions
