class Solution:
    def maxHeight(self, cuboids: List[List[int]]) -> int:
        # Sort each cuboid's dimensions to ensure consistency
        for cuboid in cuboids:
            cuboid.sort()

        # Sort the cuboids based on all three dimensions
        cuboids.sort()

        # Initialize a DP array where dp[i] represents the maximum height achievable with the first i cuboids
        dp = [0] * len(cuboids)

        # The height of the i-th cuboid is its last dimension after sorting
        for i in range(len(cuboids)):
            dp[i] = cuboids[i][2]
            for j in range(i):
                # Check if cuboid j can be placed below cuboid i
                if cuboids[j][0] <= cuboids[i][0] and cuboids[j][1] <= cuboids[i][1] and cuboids[j][2] <= cuboids[i][2]:
                    dp[i] = max(dp[i], dp[j] + cuboids[i][2])

        return max(dp)
