class Solution:
    def countWays(self, nums: List[int]) -> int:
        nums.sort()
        n = len(nums)
        res = 0

        # Check for the case where we select 0 students
        if nums[0] > 0:
            res += 1

        # Check for the case where we select all students
        if nums[-1] < n:
            res += 1

        # Check for all possible group sizes between 1 and n-1
        for k in range(1, n):
            # Find the number of students where nums[i] == k
            left = 0
            right = n
            while left < right:
                mid = (left + right) // 2
                if nums[mid] < k:
                    left = mid + 1
                else:
                    right = mid
            count = left
            # Check if there are students with nums[i] == k
            if count > 0:
                # Check if the number of students with nums[i] < k is >= k
                left = 0
                right = n
                while left < right:
                    mid = (left + right) // 2
                    if nums[mid] < k:
                        left = mid + 1
                    else:
                        right = mid
                if left >= k:
                    res += 1

        return res
