from typing import List
from collections import deque

class Solution:
    def maximumDetonation(self, bombs: List[List[int]]) -> int:
        # Build a graph where an edge from A to B means detonating A will detonate B
        graph = {i: [] for i in range(len(bombs))}

        for i in range(len(bombs)):
            x1, y1, r1 = bombs[i]
            for j in range(len(bombs)):
                if i == j:
                    continue
                x2, y2, _ = bombs[j]
                # Check if bomb j is within the range of bomb i
                dx = x1 - x2
                dy = y1 - y2
                distance_sq = dx * dx + dy * dy
                if distance_sq <= r1 * r1:
                    graph[i].append(j)

        # BFS to find the maximum number of bombs detonated starting from each bomb
        max_detonated = 0
        for start in range(len(bombs)):
            visited = set()
            queue = deque([start])
            visited.add(start)
            while queue:
                current = queue.popleft()
                for neighbor in graph[current]:
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)
            max_detonated = max(max_detonated, len(visited))

        return max_detonated
