class Solution:
    def countSubarrays(self, nums: List[int], k: int) -> int:
        max_val = max(nums)
        count = defaultdict(int)
        result = 0
        left = 0

        for right in range(len(nums)):
            if nums[right] == max_val:
                count[nums[right]] += 1

            while count[max_val] >= k:
                if nums[left] == max_val:
                    count[nums[left]] -= 1
                left += 1

            result += left

        return result
