class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Create a set of all prefixes for arr1
        prefixes_arr1 = set()
        for num in arr1:
            s = str(num)
            for i in range(1, len(s) + 1):
                prefixes_arr1.add(s[:i])

        # Check all prefixes of arr2 against the set
        max_len = 0
        for num in arr2:
            s = str(num)
            for i in range(1, len(s) + 1):
                prefix = s[:i]
                if prefix in prefixes_arr1:
                    max_len = max(max_len, i)

        return max_len
