class Solution:
    def largestNumber(self, cost: List[int], target: int) -> str:
        # Memoization dictionary to store results of subproblems
        memo = {}

        def dfs(t):
            if t == 0:
                return ""  # Empty string means we've used up the target
            if t < 0:
                return None  # Invalid, we overspent the target
            if t in memo:
                return memo[t]

            max_str = ""
            for i in range(9):
                # If the cost is 0, we can't use this digit (since it would not contribute to the target)
                if cost[i] == 0:
                    continue
                res = dfs(t - cost[i])
                if res is not None:
                    # Try to build the largest number by choosing the largest digit first
                    current = str(i + 1) + res
                    if len(current) > len(max_str) or (len(current) == len(max_str) and current > max_str):
                        max_str = current
            memo[t] = max_str
            return max_str

        result = dfs(target)
        return result if result else "0"
