from typing import List

class Solution:
    def goodIndices(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)
        # Arrays to store the length of non-increasing and non-decreasing sequences ending at each index
        non_increasing = [1] * n
        non_decreasing = [1] * n

        # Calculate non-increasing lengths
        for i in range(1, n):
            if nums[i] <= nums[i - 1]:
                non_increasing[i] = non_increasing[i - 1] + 1

        # Calculate non-decreasing lengths
        for i in range(1, n):
            if nums[i] >= nums[i - 1]:
                non_decreasing[i] = non_decreasing[i - 1] + 1

        # Check for good indices
        result = []
        for i in range(k, n - k):
            # Check if the previous k elements are non-increasing
            if non_increasing[i - 1] >= k:
                # Check if the next k elements are non-decreasing
                if non_decreasing[i] >= k:
                    result.append(i)

        return result
