from typing import List

class Solution:
    def maxOperations(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 2:
            return 0

        # Try all possible initial operation scores
        # The initial score can only be from the first two elements, last two elements, or first and last
        # So we try all three possibilities and compute the max operations for each
        # We use memoization to avoid recomputation

        from functools import lru_cache

        @lru_cache(None)
        def dfs(left, right, score):
            if left >= right:
                return 0
            res = 0
            # Try first two
            if nums[left] + nums[left + 1] == score:
                res = max(res, 1 + dfs(left + 2, right, score))
            # Try last two
            if nums[right] + nums[right - 1] == score:
                res = max(res, 1 + dfs(left, right - 2, score))
            # Try first and last
            if nums[left] + nums[right] == score:
                res = max(res, 1 + dfs(left + 1, right - 1, score))
            return res

        # Try all three possible initial scores
        return max(dfs(0, n - 1, nums[0] + nums[1]), 
                   dfs(0, n - 1, nums[0] + nums[-1]), 
                   dfs(0, n - 1, nums[-2] + nums[-1]))
