                return abs(nums[0] - 24) < 1e-6
            for i in range(len(nums)):
                for j in range(len(nums)):
                    if i != j:
                        a, b = nums[i], nums[j]
                        new_nums = []
                        for k in range(len(nums)):
                            if k != i and k != j:
                                new_nums.append(nums[k])
                        # Addition
                        new_nums.append(a + b)
                        if backtrack(new_nums):
                            return True
                        # Subtraction
                        new_nums = []
                        for k in range(len(nums)):
                            if k != i and k != j:
                                new_nums.append(nums[k])
                        new_nums.append(a - b)
                        if backtrack(new_nums):
                            return True
                        # Multiplication
                        new_nums = []
                        for k in range(len(nums)):
                            if k != i and k != j:
                                new_nums.append(nums[k])
