from typing import List

class Solution:
    def minCostII(self, costs: List[List[int]]) -> int:
        n = len(costs)
        if n == 0:
            return 0
        k = len(costs[0])
        if k == 0:
            return 0

        # dp[i][j] represents the minimum cost to paint up to house i, with color j
        dp = [[0] * k for _ in range(n)]

        # Initialize first house
        for j in range(k):
            dp[0][j] = costs[0][j]

        # Iterate over the rest of the houses
        for i in range(1, n):
            # Find the minimum and second minimum cost from previous row
            min1 = float('inf')
            min2 = float('inf')
            for j in range(k):
                if dp[i-1][j] < min1:
                    min2 = min1
                    min1 = dp[i-1][j]
                elif dp[i-1][j] < min2:
                    min2 = dp[i-1][j]

            # Update current row
            for j in range(k):
                # For each color j, we can't use the same color as previous
                # So we add the current cost to the second minimum of previous
                dp[i][j] = costs[i][j] + min2 if dp[i-1][j] == min1 else costs[i][j] + min1

        # The answer is the minimum of the last row
        return min(dp[-1])
