class Solution:
    def minimumString(self, a: str, b: str, c: str) -> str:
        def merge(x: str, y: str) -> str:
            # Try all possible ways to merge x and y
            # x can be before y or y can be before x
            # Also, check if one is a substring of the other
            if y in x:
                return x
            if x in y:
                return y
            # Try to merge y into x
            for i in range(len(x), 0, -1):
                if x[-i:] == y[:i]:
                    return x + y[i:]
            # Try to merge x into y
            for i in range(len(y), 0, -1):
                if y[-i:] == x[:i]:
                    return y + x[i:]
            return x + y  # Fallback if no overlap

        # Generate all 6 permutations of the three strings
        from itertools import permutations
        candidates = []
        for perm in permutations([a, b, c]):
            # Merge the first two
            merged = merge(perm[0], perm[1])
            # Merge the result with the third
            final = merge(merged, perm[2])
            candidates.append(final)

        # Find the minimum length candidate
        min_len = min(len(c) for c in candidates)
        min_candidates = [c for c in candidates if len(c) == min_len]
        # Return the lex smallest one
        return min(min_candidates)
