from typing import List
from collections import defaultdict

class Solution:
    def countCornerRectangles(self, grid: List[List[int]]) -> int:
        rows = len(grid)
        cols = len(grid[0])
        count = 0
        # Use a dictionary to store the positions of 1s in each row
        ones_positions = defaultdict(list)

        for i in range(rows):
            for j in range(cols):
                if grid[i][j] == 1:
                    ones_positions[i].append(j)

        # For each pair of rows, check if they have common columns with 1s
        for i in range(rows):
            for j in range(i + 1, rows):
                # Get the columns with 1s in both rows
                common_cols = set(ones_positions[i]) & set(ones_positions[j])
                # Number of rectangles between these two rows is combinations of 2 from common_cols
                count += len(common_cols) * (len(common_cols) - 1) // 2

        return count
