class Solution:
    def numIslands2(self, m: int, n: int, positions: List[List[int]]) -> List[int]:
        parent = {}
        rank = {}
        result = []
        count = 0

        def find(node):
            if parent[node] != node:
                parent[node] = find(parent[node])
            return parent[node]

        def union(a, b):
            nonlocal count
            root_a = find(a)
            root_b = find(b)
            if root_a == root_b:
                return
            if rank[root_a] < rank[root_b]:
                parent[root_a] = root_b
            else:
                parent[root_b] = root_a
                if rank[root_a] == rank[root_b]:
                    rank[root_a] += 1
            count -= 1

        for r, c in positions:
            node = (r, c)
            if node in parent:
                result.append(count)
                continue
            parent[node] = node
            rank[node] = 1
            count += 1

            # Check top
            if (r - 1, c) in parent:
                union(node, (r - 1, c))
            # Check bottom
            if (r + 1, c) in parent:
                union(node, (r + 1, c))
            # Check left
            if (r, c - 1) in parent:
                union(node, (r, c - 1))
            # Check right
            if (r, c + 1) in parent:
                union(node, (r, c + 1))

            result.append(count)

        return result
