class Solution:
    def countAlternatingSubarrays(self, nums: List[int]) -> int:
        count = 0
        length = len(nums)
        if length == 0:
            return 0
        # Start with the first element
        count += 1
        # Iterate from the second element
        for i in range(1, length):
            # If current element is different from previous, increment the count
            if nums[i] != nums[i - 1]:
                count += 1
            else:
                # If same, reset count to 1 (current element alone)
                count = 1
        return count
