class Solution:
    def idealArrays(self, n: int, maxValue: int) -> int:
        MOD = 10**9 + 7

        from collections import defaultdict
        import math

        # Precompute the number of divisors for each number up to maxValue
        divisors = [0] * (maxValue + 1)
        for i in range(1, maxValue + 1):
            for j in range(i, maxValue + 1, i):
                divisors[j] += 1

        # Precompute factorials and inverse factorials for combinations
        max_fact = maxValue
        fact = [1] * (max_fact + 1)
        inv_fact = [1] * (max_fact + 1)
        for i in range(1, max_fact + 1):
            fact[i] = fact[i-1] * i % MOD
        inv_fact[max_fact] = pow(fact[max_fact], MOD-2, MOD)
        for i in range(max_fact-1, -1, -1):
            inv_fact[i] = inv_fact[i+1] * (i+1) % MOD

        def comb(k, n):
            # C(n, k) = n! / (k! * (n-k)!)
            if k < 0 or k > n:
                return 0
            return fact[n] * inv_fact[k] % MOD * inv_fact[n - k] % MOD

        # For each number up to maxValue, count the number of ideal arrays that end with it
        # We use dynamic programming where dp[i] is the number of ideal arrays ending with i
        dp = [0] * (maxValue + 1)
        for i in range(1, maxValue + 1):
            dp[i] = 1  # Each number can be the starting element
            for d in range(1, int(i**0.5) + 1):
                if i % d == 0:
                    if d != i:
                        dp[i] += dp[d]
                    if i // d != d and i // d != i:
                        dp[i] += dp[i // d]
            dp[i] %= MOD

        # The answer is the sum of dp[i] for all i from 1 to maxValue
        return sum(dp[1:maxValue+1]) % MOD
