class Solution:
    def smallestSubsequence(self, s: str) -> str:
        from collections import Counter

        count = Counter(s)
        stack = []
        seen = set()

        for char in s:
            if char in seen:
                count[char] -= 1
                continue

            while stack and char < stack[-1] and count[stack[-1]] > 0:
                removed = stack.pop()
                seen.remove(removed)

            stack.append(char)
            seen.add(char)
            count[char] -= 1

        return ''.join(stack)
