class Solution:
    def paintWalls(self, cost: List[int], time: List[int]) -> int:
        n = len(cost)

        @lru_cache(None)
        def dp(index, remaining_time, walls_painted):
            # If we've painted all walls, return 0
            if walls_painted >= n:
                return 0
            # If we've processed all walls, return infinity if not all painted
            if index >= n:
                return float('inf') if walls_painted < n else 0

            # Option 1: Use the paid painter for this wall
            option1 = dp(index + 1, remaining_time - time[index], walls_painted + 1) + cost[index]

            # Option 2: Use the free painter for this wall (only if paid painter is busy)
            option2 = dp(index + 1, remaining_time - 1, walls_painted)

            return min(option1, option2)

        # Start with 0 index, 0 time remaining, 0 walls painted
        return dp(0, 0, 0)
