from collections import defaultdict, deque
from typing import List

class Solution:
    def alienOrder(self, words: List[str]) -> str:
        # Build the graph
        graph = defaultdict(list)
        in_degree = defaultdict(int)
        all_chars = set()

        # Step 1: Build the graph from the words
        for i in range(len(words) - 1):
            word1 = words[i]
            word2 = words[i + 1]
            min_len = min(len(word1), len(word2))
            # Find the first differing character
            for j in range(min_len):
                c1, c2 = word1[j], word2[j]
                if c1 != c2:
                    # Add an edge from c1 to c2
                    if c2 not in graph[c1]:
                        graph[c1].append(c2)
                        in_degree[c2] += 1
                    break
            # Add all characters to all_chars
            for c in word1 + word2:
                all_chars.add(c)

        # Step 2: Topological sort using Kahn's algorithm
        queue = deque()
        for char in all_chars:
            if in_degree.get(char, 0) == 0:
                queue.append(char)

        result = []
        while queue:
            node = queue.popleft()
            result.append(node)
            for neighbor in graph[node]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        # Check if the result contains all characters
        if len(result) != len(all_chars):
            return ""

        return ''.join(result)
