class Solution:
    def maxSubstringLength(self, s: str) -> int:
        from collections import defaultdict

        n = len(s)
        last_occurrence = defaultdict(int)
        for i, c in enumerate(s):
            last_occurrence[c] = i

        # For each position, track the last occurrence of each character
        # and try to find the longest valid substring
        max_len = -1
        for i in range(n):
            char_count = defaultdict(int)
            unique_chars = set()
            for j in range(i, n):
                c = s[j]
                if char_count[c] == 0:
                    unique_chars.add(c)
                char_count[c] += 1

                # Check if all characters in the current substring are not present outside
                all_unique = True
                for ch in unique_chars:
                    if last_occurrence[ch] > j:
                        all_unique = False
                        break
                if all_unique:
                    max_len = max(max_len, j - i + 1)

        return max_len if max_len != 0 else -1
