class Solution:
    def robotWithString(self, s: str) -> str:
        # Calculate the frequency of each character
        freq = [0] * 26
        for c in s:
            freq[ord(c) - ord('a')] += 1

        # Pointer for the frequency array
        ptr = 0

        # Stack to simulate the robot's string t
        stack = []

        # Iterate through the string s
        for i in range(len(s)):
            # Push current character to the stack
            stack.append(s[i])

            # Check if the current character is the smallest possible
            # to pop from the stack to the result
            while ptr < 26 and freq[ptr] > 0:
                # If the current top of the stack is smaller than or equal to the current character
                if stack[-1] == chr(ord('a') + ptr):
                    # Pop from stack and add to result
                    stack.pop()
                    freq[ptr] -= 1
                    ptr += 1
                else:
                    break

        # After processing all characters, pop any remaining characters from the stack
        while ptr < 26:
            if stack and stack[-1] == chr(ord('a') + ptr):
                stack.pop()
                freq[ptr] -= 1
                ptr += 1
            else:
                break

        # Now, pop all remaining characters from the stack
        while stack:
            stack.pop()

        # The result is built in reverse order, so reverse it
        return ''.join(stack[::-1])
