from typing import List

class Solution:
    def asteroidCollision(self, asteroids: List[int]) -> List[int]:
        stack = []
        for asteroid in asteroids:
            # If current asteroid is moving to the left (negative)
            # and the stack is not empty and the top asteroid is moving to the right (positive)
            # then a collision may happen
            while stack and asteroid < 0 and stack[-1] > 0:
                # Compare the sizes of the current asteroid and the top of the stack
                if abs(asteroid) > stack[-1]:
                    stack.pop()  # The top asteroid explodes
                elif abs(asteroid) == stack[-1]:
                    stack.pop()  # Both asteroids explode
                    break  # No need to check further
                else:
                    # The current asteroid explodes
                    asteroid = 0
                    break
            if asteroid != 0:
                stack.append(asteroid)
        return stack
