class Solution:
    def numberOfBeautifulIntegers(self, low: int, high: int, k: int) -> int:
        from functools import lru_cache

        def count_beautiful(n: int, k: int) -> int:
            # We use digit DP to count beautiful numbers up to n
            digits = list(map(int, str(n)))
            length = len(digits)

            @lru_cache(None)
            def dp(pos, even_count, odd_count, mod, tight, leading_zero):
                if pos == length:
                    return 1 if even_count == odd_count and mod == 0 else 0

                limit = digits[pos] if tight else 9
                total = 0

                for d in range(0, limit + 1):
                    new_tight = tight and (d == limit)
                    new_leading_zero = leading_zero and (d == 0)
                    new_even = even_count
                    new_odd = odd_count
                    new_mod = mod

                    if not new_leading_zero:
                        if d % 2 == 0:
                            new_even += 1
                        else:
                            new_odd += 1
                        new_mod = (mod * 10 + d) % k

                    total += dp(pos + 1, new_even, new_odd, new_mod, new_tight, new_leading_zero)

                return total

            return dp(0, 0, 0, 0, True, True)

        return count_beautiful(high, k) - count_beautiful(low - 1, k)
