class Solution:
    def maxTurbulenceSize(self, arr: List[int]) -> int:
        n = len(arr)
        if n == 1:
            return 1

        max_len = 1
        current_len = 1
        prev_diff = 0  # 0 for equal, 1 for up, -1 for down

        for i in range(1, n):
            current_diff = 1 if arr[i] > arr[i - 1] else -1 if arr[i] < arr[i - 1] else 0

            if current_diff == 0:
                current_len = 1
            elif current_diff == -prev_diff:
                current_len += 1
            else:
                current_len = 2

            prev_diff = current_diff
            max_len = max(max_len, current_len)

        return max_len
