class Solution:
    def shortestWay(self, source: str, target: str) -> int:
        # Check if all characters in target are present in source
        source_set = set(source)
        for c in target:
            if c not in source_set:
                return -1

        count = 0
        target_index = 0
        n = len(target)

        while target_index < n:
            count += 1
            source_index = 0
            # Try to match as much of target as possible in one pass of source
            while source_index < len(source) and target_index < n:
                if source[source_index] == target[target_index]:
                    target_index += 1
                source_index += 1

        return count
