class Solution:
    def numIslands2(self, m: int, n: int, positions: List[List[int]]) -> List[int]:
        parent = {}
        rank = {}
        result = []
        count = 0

        def find(p):
            if parent[p] != p:
                parent[p] = find(parent[p])
            return parent[p]

        def union(p, q):
            nonlocal count
            root_p = find(p)
            root_q = find(q)
            if root_p == root_q:
                return
            if rank[root_p] < rank[root_q]:
                parent[root_p] = root_q
            elif rank[root_p] > rank[root_q]:
                parent[root_q] = root_p
            else:
                parent[root_q] = root_p
                rank[root_p] += 1
            count -= 1

        for r, c in positions:
            pos = r * n + c
            if pos in parent:
                result.append(count)
                continue
            parent[pos] = pos
            rank[pos] = 1
            count += 1

            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nr, nc = r + dx, c + dy
                neighbor_pos = nr * n + nc
                if 0 <= nr < m and 0 <= nc < n and neighbor_pos in parent:
                    union(pos, neighbor_pos)
            result.append(count)

        return result
