class Solution:
    def longestSubsequence(self, s: str, k: int) -> int:
        max_len = 0
        value = 0
        for c in s:
            if c == '0':
                # Adding a '0' doesn't increase the value, but increases the length
                max_len += 1
            else:
                # Adding a '1' increases the value
                # Check if we can add this '1' without exceeding k
                # We can only add it if the new value is <= k
                new_value = value * 2 + 1
                if new_value <= k:
                    value = new_value
                    max_len += 1
        return max_len
