class Solution:
    def minArea(self, image: List[List[str]], x: int, y: int) -> int:
        m, n = len(image), len(image[0])
        top = 0
        bottom = m - 1
        left = 0
        right = n - 1

        # Find top boundary
        while top <= bottom:
            if any(image[top][j] == '1' for j in range(n)):
                break
            top += 1

        # Find bottom boundary
        while top <= bottom:
            if any(image[bottom][j] == '1' for j in range(n)):
                break
            bottom -= 1

        # Find left boundary
        while left <= right:
            if any(image[i][left] == '1' for i in range(m)):
                break
            left += 1

        # Find right boundary
        while left <= right:
            if any(image[i][right] == '1' for i in range(m)):
                break
            right -= 1

        return (bottom - top + 1) * (right - left + 1)
