from typing import List
from collections import defaultdict, deque

class Solution:
    def countSubgraphsForEachDiameter(self, n: int, edges: List[List[int]]) -> List[int]:
        # Build adjacency list
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        # Function to compute the maximum distance between any two nodes in a subset
        def max_distance(subset):
            # BFS to find the farthest node from a starting node
            def bfs(start):
                visited = {start}
                queue = deque([(start, 0)])
                farthest_node = start
                max_dist = 0
                while queue:
                    node, dist = queue.popleft()
                    for neighbor in graph[node]:
                        if neighbor not in visited:
                            visited.add(neighbor)
                            queue.append((neighbor, dist + 1))
                            if dist + 1 > max_dist:
                                max_dist = dist + 1
                                farthest_node = neighbor
                return farthest_node, max_dist

            # Find the farthest node from an arbitrary node in the subset
            start = next(iter(subset))
            farthest_node, _ = bfs(start)
            # Now find the farthest node from the farthest_node
            _, max_d = bfs(farthest_node)
            return max_d

        # Generate all possible non-empty subsets of nodes
        result = [0] * (n - 1)
        for mask in range(1, 1 << n):
            subset = set()
            for i in range(n):
                if mask & (1 << i):
                    subset.add(i + 1)  # nodes are 1-indexed

            if len(subset) < 2:
                continue

            # Check if the subset forms a valid subtree (connected)
            visited = set()
            queue = deque([next(iter(subset))])
            visited.add(next(iter(subset)))
            while queue:
                node = queue.popleft()
                for neighbor in graph[node]:
                    if neighbor in subset and neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)
            if visited != subset:
                continue

            # Compute the max distance in the subtree
            d = max_distance(subset)
            if d <= n - 1:
                result[d - 1] += 1

        return result
