class Solution:
    def beautifulPartitions(self, s: str, k: int, minLength: int) -> int:
        MOD = 10**9 + 7
        prime_digits = {'2', '3', '5', '7'}
        n = len(s)

        # Preprocess the string to find valid positions
        # We can only split between positions where the current character is non-prime
        # So we first check if the first character is prime and the last character is non-prime
        if s[0] not in prime_digits or s[-1] in prime_digits:
            return 0

        # Precompute a list of valid split points
        valid_split_positions = []
        for i in range(n - 1):
            if s[i] in prime_digits and s[i + 1] not in prime_digits:
                valid_split_positions.append(i)

        # Now we can use dynamic programming
        # dp[i][j] = number of ways to partition first i characters into j parts
        dp = [[0] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 1

        for i in range(1, n + 1):
            for j in range(1, k + 1):
                # Try to end a partition at i
                # The partition must be at least minLength long
                for pos in range(i - minLength, i):
                    if pos == 0:
                        if s[pos] in prime_digits and s[i - 1] not in prime_digits:
                            dp[i][j] = (dp[i][j] + dp[pos][j - 1]) % MOD
                    else:
                        if s[pos] in prime_digits and s[i - 1] not in prime_digits:
                            dp[i][j] = (dp[i][j] + dp[pos][j - 1]) % MOD

        return dp[n][k]
