class Solution:
    def reachingPoints(self, sx: int, sy: int, tx: int, ty: int) -> bool:
        # If tx is less than sx or ty is less than sy, it's impossible
        while tx > sx and ty > sy:
            # Reduce tx and ty by the larger of the two
            if tx > ty:
                tx %= ty
            else:
                ty %= tx

        # Now, check if we can reach (sx, sy) by subtracting multiples of sy from ty or sx from tx
        if tx == sx and ty == sy:
            return True
        elif tx == sx:
            # We can only subtract sy from ty
            return (ty - sy) % sx == 0
        elif ty == sy:
            # We can only subtract sx from tx
            return (tx - sx) % sy == 0
        else:
            return False
