class Solution:
    def knightProbability(self, n: int, k: int, row: int, column: int) -> float:
        # Define the 8 possible knight moves
        directions = [(-2, -1), (-2, 1), (-1, -2), (-1, 2), (1, -2), (1, 2), (2, -1), (2, 1)]

        # Initialize a 3D DP table: dp[step][r][c] = probability of being on (r, c) after 'step' moves
        dp = [[[0.0 for _ in range(n)] for _ in range(n)] for _ in range(k + 1)]

        # Base case: probability of being on the starting position with 0 moves is 1.0
        dp[0][row][column] = 1.0

        # Iterate over each move
        for step in range(k):
            for r in range(n):
                for c in range(n):
                    if dp[step][r][c] > 0:
                        # Try all 8 directions
                        for dr, dc in directions:
                            nr, nc = r + dr, c + dc
                            if 0 <= nr < n and 0 <= nc < n:
                                dp[step + 1][nr][nc] += dp[step][r][c] / 8.0

        # Sum up the probabilities of being on the board after k moves
        total_probability = sum(dp[k][r][c] for r in range(n) for c in range(n))

        return total_probability
