from typing import List

class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        n = len(num)
        for i in range(1, n - 1):
            if num[0] == '0' and i > 1:
                continue  # Skip leading zeros
            first = int(num[:i])
            if first > 2**31 - 1:
                continue
            for j in range(i + 1, n):
                if num[i] == '0' and j > i + 1:
                    continue  # Skip leading zeros
                second = int(num[i:j])
                if second > 2**31 - 1:
                    continue
                # Now try to build the sequence
                fib = [first, second]
                k = j
                while k < n:
                    next_val = fib[-1] + fib[-2]
                    if next_val > 2**31 - 1:
                        break
                    next_str = str(next_val)
                    if num[k:].startswith(next_str):
                        fib.append(next_val)
                        k += len(next_str)
                    else:
                        break
                if len(fib) >= 3 and k == n:
                    return fib
        return []
