class Solution:
    def missingElement(self, nums: List[int], k: int) -> int:
        # Calculate the number of missing elements up to index i
        def missing_up_to(i):
            return nums[i] - nums[0] - i

        # Binary search to find the position where the kth missing number lies
        left, right = 0, len(nums) - 1
        while left < right:
            mid = (left + right) // 2
            if missing_up_to(mid) < k:
                left = mid + 1
            else:
                right = mid

        # The kth missing number is between nums[left-1] and nums[left]
        return nums[left] + (k - missing_up_to(left))
