class Solution:
    def peopleAwareOfSecret(self, n: int, delay: int, forget: int) -> int:
        MOD = 10**9 + 7
        # dp[i] will represent the number of people who start sharing the secret on day i
        dp = [0] * (n + 1)
        dp[1] = 1  # On day 1, one person knows the secret

        for day in range(1, n + 1):
            if dp[day] == 0:
                continue
            # The person can start sharing from day + delay to day + forget - 1
            start = day + delay
            end = day + forget - 1
            if start > n:
                continue
            if end > n:
                end = n
            # The number of days they can share is end - start + 1
            share_days = end - start + 1
            # Each day they share, they add new people who will start sharing on that day
            for share_day in range(start, end + 1):
                dp[share_day] = (dp[share_day] + dp[day]) % MOD

        # Sum all people who know the secret on day n
        total = 0
        for day in range(1, n + 1):
            # A person who started on day 'day' will forget on day 'day + forget - 1'
            if day + forget - 1 > n:
                total = (total + dp[day]) % MOD
        return total
