class Solution:
    def encode(self, s: str) -> str:
        n = len(s)

        # dp[i][j] will store the shortest encoded string for s[i:j+1]
        dp = [["" for _ in range(n)] for _ in range(n)]

        for length in range(1, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                substr = s[i:j+1]

                # Case 1: No encoding
                dp[i][j] = substr

                # Case 2: Try splitting the substring into two parts
                for k in range(i, j):
                    if len(dp[i][k]) + len(dp[k+1][j]) < len(dp[i][j]):
                        dp[i][j] = dp[i][k] + dp[k+1][j]

                # Case 3: Try to find a repeating pattern
                for repeat in range(2, length + 1):
                    if length % repeat == 0:
                        part = substr[:length // repeat]
                        if part * repeat == substr:
                            encoded = f"{repeat}[{dp[i][i + length // repeat - 1]}]"
                            if len(encoded) < len(dp[i][j]):
                                dp[i][j] = encoded

        return dp[0][n-1]
