from typing import List

class Solution:
    def maximumGood(self, statements: List[List[int]]) -> int:
        n = len(statements)
        max_good = 0

        # Try all possible subsets of good people
        for mask in range(1 << n):
            good = [i for i in range(n) if (mask >> i) & 1]
            valid = True

            for i in good:
                for j in range(n):
                    if j == i:
                        continue
                    stmt = statements[i][j]
                    if stmt == 0:
                        if (mask >> j) & 1:
                            valid = False
                            break
                    elif stmt == 1:
                        if not (mask >> j) & 1:
                            valid = False
                            break
                    # 2 means no statement, so we ignore

            if valid:
                max_good = max(max_good, len(good))

        return max_good
