from typing import List

class Solution:
    def minSideJumps(self, obstacles: List[int]) -> int:
        n = len(obstacles) - 1
        # Initialize the number of side jumps needed for each lane at point 0
        # lanes are 1, 2, 3; we start at lane 2 (index 1)
        dp = [0, 0, 0]
        dp[1] = 0  # starting at lane 2 (index 1)
        dp[0] = 1  # lane 1 requires 1 side jump to reach
        dp[2] = 1  # lane 3 requires 1 side jump to reach

        for i in range(1, n + 1):
            # Copy current dp values to new_dp
            new_dp = dp[:]
            # If current point has an obstacle in a lane, set that lane's cost to infinity
            obs = obstacles[i]
            if obs == 1:
                new_dp[0] = float('inf')
            elif obs == 2:
                new_dp[1] = float('inf')
            elif obs == 3:
                new_dp[2] = float('inf')

            # For each lane, check if we can move to another lane without side jump
            for lane in range(3):
                if new_dp[lane] == float('inf'):
                    continue
                # Try to move forward if possible
                if obstacles[i + 1] != lane + 1:
                    new_dp[lane] = min(new_dp[lane], dp[lane])
                else:
                    # Need to make a side jump
                    for other_lane in range(3):
                        if other_lane == lane:
                            continue
                        if obstacles[i + 1] != other_lane + 1:
                            new_dp[other_lane] = min(new_dp[other_lane], dp[lane] + 1)
            dp = new_dp

        return min(dp)
