class Solution:
    def robotWithString(self, s: str) -> str:
        from collections import deque

        # Step 1: Compute the frequency of each character
        freq = [0] * 26
        for c in s:
            freq[ord(c) - ord('a')] += 1

        # Step 2: Use a deque to simulate the robot's string t
        t = deque()
        result = []

        # Step 3: Iterate through the string s
        for c in s:
            t.append(c)
            # While the top of t is <= the smallest remaining character in s
            while t and freq[ord(t[-1]) - ord('a')] > 0:
                result.append(t.pop())
                freq[ord(t[-1]) - ord('a')] -= 1

        # Step 4: Pop all remaining characters from t
        while t:
            result.append(t.pop())

        return ''.join(result)
