class Solution:
    def scoreOfParentheses(self, s: str) -> int:
        stack = []
        score = 0
        for char in s:
            if char == '(':
                stack.append(score)
                score = 0
            else:
                top = stack.pop()
                if score == 0:
                    score = top + 1
                else:
                    score = top + 2 * score
        return score
