from typing import List

class Solution:
    def closestCost(self, baseCosts: List[int], toppingCosts: List[int], target: int) -> int:
        # Set to keep track of all possible topping combinations
        topping_sums = {0}

        # Generate all possible topping sums (0, 1, or 2 of each topping)
        for cost in toppingCosts:
            new_sums = set()
            for s in topping_sums:
                new_sums.add(s)
                new_sums.add(s + cost)
                new_sums.add(s + 2 * cost)
            topping_sums = new_sums

        # Now check all base + topping combinations
        closest = float('inf')
        for base in baseCosts:
            for t in topping_sums:
                total = base + t
                # Update closest based on how close we are to target
                if abs(total - target) < abs(closest - target):
                    closest = total
                elif abs(total - target) == abs(closest - target) and total < closest:
                    closest = total

        return closest
