from typing import List
import bisect

class Solution:
    def maxEnvelopes(self, envelopes: List[List[int]]) -> int:
        # Sort envelopes by width, and by height in descending order if widths are equal
        envelopes.sort(key=lambda x: (x[0], -x[1]))

        # Extract the heights to apply the Longest Increasing Subsequence (LIS) algorithm
        heights = [h for _, h in envelopes]

        # Use a patience sorting-like approach with binary search for O(n log n) complexity
        lis = []
        for h in heights:
            # Use bisect to find the first index in lis where the element is >= h
            idx = bisect.bisect_left(lis, h)
            if idx == len(lis):
                lis.append(h)
            else:
                lis[idx] = h
        return len(lis)
