from typing import List
from functools import lru_cache

class Solution:
    def maxTastiness(self, price: List[int], tastiness: List[int], maxAmount: int, maxCoupons: int) -> int:
        n = len(price)

        @lru_cache(None)
        def dp(index, coupons_used, amount_spent):
            if index == n:
                return 0

            # Option 1: Skip the current fruit
            skip = dp(index + 1, coupons_used, amount_spent)

            # Option 2: Buy the fruit without using a coupon
            if amount_spent + price[index] <= maxAmount:
                buy_no_coupon = tastiness[index] + dp(index + 1, coupons_used, amount_spent + price[index])
                skip = max(skip, buy_no_coupon)

            # Option 3: Buy the fruit using a coupon (if available)
            if coupons_used < maxCoupons:
                coupon_price = price[index] // 2
                if amount_spent + coupon_price <= maxAmount:
                    buy_with_coupon = tastiness[index] + dp(index + 1, coupons_used + 1, amount_spent + coupon_price)
                    skip = max(skip, buy_with_coupon)

            return skip

        return dp(0, 0, 0)
