            # Pressing 'A' gives us 1 'A'
            dp[i] = dp[i - 1] + 1
            # Try all possible previous states where we could have used Ctrl+A, Ctrl+C, and then Ctrl+V
            for j in range(i - 3, 0, -1):
                dp[i] = max(dp[i], dp[j] + dp[i - j - 3])

        return dp[n]
