from typing import List
from functools import lru_cache

class Solution:
    def maxTastiness(self, price: List[int], tastiness: List[int], maxAmount: int, maxCoupons: int) -> int:
        n = len(price)

        @lru_cache(None)
        def dp(index, remaining_amount, coupons_left):
            if index == n:
                return 0

            # Option 1: Skip the current fruit
            skip = dp(index + 1, remaining_amount, coupons_left)

            # Option 2: Buy the current fruit without using a coupon
            cost_without_coupon = price[index]
            if cost_without_coupon <= remaining_amount:
                buy_without = tastiness[index] + dp(index + 1, remaining_amount - cost_without_coupon, coupons_left)
                skip = max(skip, buy_without)

            # Option 3: Buy the current fruit using a coupon (if available)
            cost_with_coupon = price[index] // 2
            if cost_with_coupon <= remaining_amount and coupons_left > 0:
                buy_with = tastiness[index] + dp(index + 1, remaining_amount - cost_with_coupon, coupons_left - 1)
                skip = max(skip, buy_with)

            return skip

        return dp(0, maxAmount, maxCoupons)
