from typing import List
from functools import lru_cache

class Solution:
    def maxTotalReward(self, rewardValues: List[int]) -> int:
        rewardValues.sort()
        n = len(rewardValues)
        unique_rewards = list(sorted(set(rewardValues)))
        m = len(unique_rewards)

        @lru_cache(None)
        def dp(i, x):
            if i == m:
                return x
            # Option 1: skip the current reward
            res = dp(i + 1, x)
            # Option 2: take the current reward if possible
            if unique_rewards[i] > x:
                res = max(res, dp(i + 1, x + unique_rewards[i]))
            return res

        return dp(0, 0)
