from typing import List

class Solution:
    def countCornerRectangles(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        count = 0
        ones_in_rows = [sum(row) for row in grid]

        for i in range(m):
            if ones_in_rows[i] < 2:
                continue
            ones_in_row_i = [j for j in range(n) if grid[i][j] == 1]
            for j in range(i + 1, m):
                if ones_in_rows[j] < 2:
                    continue
                ones_in_row_j = [k for k in range(n) if grid[j][k] == 1]
                # Count common columns between row i and row j
                common = set(ones_in_row_i) & set(ones_in_row_j)
                count += len(common) * (len(common) - 1) // 2
        return count
