from typing import List

class Solution:
    def longestLine(self, mat: List[List[int]]) -> int:
        if not mat or not mat[0]:
            return 0

        m, n = len(mat), len(mat[0])
        # Directions: right, down, diagonal, anti-diagonal
        directions = [(0, 1), (1, 0), (1, 1), (1, -1)]
        # We'll use a 3D array to keep track of counts for each direction
        # [row][col][direction] = count
        dp = [[[0]*4 for _ in range(n)] for _ in range(m)]

        max_len = 0

        for i in range(m):
            for j in range(n):
                if mat[i][j] == 1:
                    # Update for each direction
                    for d in range(4):
                        dx, dy = directions[d]
                        ni, nj = i + dx, j + dy
                        if 0 <= ni < m and 0 <= nj < n:
                            dp[i][j][d] = dp[ni][nj][d] + 1
                        else:
                            dp[i][j][d] = 1
                        max_len = max(max_len, dp[i][j][d])

        return max_len
