class Solution:
    def simulationResult(self, windows: List[int], queries: List[int]) -> List[int]:
        # Use a set to track which windows have been processed to avoid duplicates
        seen = set()
        # Iterate through each query and move the window to the front if not already there
        for q in queries:
            if q not in seen:
                windows.remove(q)
                windows.insert(0, q)
                seen.add(q)
        return windows
