class Solution:
    def equalDigitFrequency(self, s: str) -> int:
        from collections import Counter

        n = len(s)
        seen = set()
        result = 0

        for i in range(n):
            freq = Counter()
            for j in range(i, n):
                freq[s[j]] += 1
                # Check if all characters have the same frequency
                unique_freq = set(freq.values())
                if len(unique_freq) == 1:
                    substr = s[i:j+1]
                    if substr not in seen:
                        seen.add(substr)
                        result += 1

        return result
