class Solution:
    def breakPalindrome(self, palindrome: str) -> str:
        n = len(palindrome)
        if n == 1:
            return ""

        # Convert string to list for easier manipulation
        s = list(palindrome)

        # Try to replace the first character that can be changed to 'a'
        for i in range(n // 2):
            if s[i] != 'a':
                s[i] = 'a'
                return ''.join(s)

        # If all first half characters are 'a', replace the last character with 'b'
        s[-1] = 'b'
        return ''.join(s)
