class Solution:
    def numberOfArrays(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        dp = [0] * (n + 1)
        dp[0] = 1  # Base case: empty string can be formed in 1 way

        for i in range(1, n + 1):
            # Try all possible lengths of numbers ending at position i
            for j in range(i - 1, max(-1, i - len(str(k))) - 1, -1):
                if j < 0:
                    break
                num_str = s[j:i]
                if num_str[0] == '0' and len(num_str) > 1:
                    continue  # Skip leading zeros
                if int(num_str) <= k:
                    dp[i] = (dp[i] + dp[j]) % MOD

        return dp[n]
