class Solution:
    def deleteString(self, s: str) -> int:
        n = len(s)
        dp = [1] * n  # dp[i] is the maximum number of operations for substring s[i:]

        # We will use a suffix array to store the longest common prefix lengths
        # between s[i:] and s[j:] for all i < j
        lcp = [0] * n
        for i in range(n - 2, -1, -1):
            if s[i] == s[i + 1]:
                lcp[i] = lcp[i + 1] + 1
            else:
                lcp[i] = 0

        for i in range(n - 2, -1, -1):
            if lcp[i] > 0:
                dp[i] = dp[i + lcp[i]] + 1

        return dp[0]
