class Solution:
    def reinitializePermutation(self, n: int) -> int:
        # We need to find the minimum number of operations to return perm to its original state.
        # We simulate the operation and track the positions of elements to find cycles.
        # The answer is the least common multiple (LCM) of the lengths of all cycles.

        visited = [False] * n
        result = 0

        for i in range(1, n):  # start from 1 to avoid 0 (which is always fixed)
            if not visited[i]:
                cycle_length = 0
                current = i
                while not visited[current]:
                    visited[current] = True
                    current = self.getNextPosition(current, n)
                    cycle_length += 1
                result = lcm(result, cycle_length)

        return result

    def getNextPosition(self, index: int, n: int) -> int:
        if index % 2 == 0:
            return index // 2
        else:
            return n // 2 + (index - 1) // 2

    def lcm(self, a: int, b: int) -> int:
        from math import gcd
        return a * b // gcd(a, b)
