class Solution:
    def distinctEchoSubstrings(self, text: str) -> int:
        n = len(text)
        seen = set()
        result = 0

        for i in range(n):
            for j in range(i + 1, n + 1):
                length = j - i
                if length % 2 != 0:
                    continue
                half = length // 2
                if text[i:i + half] == text[i + half:j]:
                    seen.add(text[i:j])

        return len(seen)
