class Solution:
    def minimumNumbers(self, num: int, k: int) -> int:
        if num == 0:
            return 0

        # If k is 0, we can only use 0s, but since the problem says positive integers, this is not allowed
        if k == 0:
            return -1

        # We need to find the minimum number of numbers ending with k that sum to num
        # Let's try all possible counts of numbers (from 1 to num // k)
        for count in range(1, num // k + 1):
            # The sum of count numbers each ending with k is at least count * k
            # We can add any multiple of 10 to each number to make the sum exactly num
            # So we check if (num - count * k) is divisible by 10
            if (num - count * k) % 10 == 0:
                return count

        return -1
