from typing import List

class Solution:
    def addNegabinary(self, arr1: List[int], arr2: List[int]) -> List[int]:
        # Convert arr1 and arr2 from base -2 to decimal
        def to_decimal(arr: List[int]) -> int:
            num = 0
            for bit in arr:
                num = num * (-2) + bit
            return num

        # Convert decimal number to base -2
        def to_base_neg2(n: int) -> List[int]:
            if n == 0:
                return [0]
            result = []
            while n != 0:
                n, remainder = divmod(n, -2)
                if remainder < 0:
                    remainder += 2
                    n += 1
                result.append(remainder)
            return result[::-1]

        # Convert both arrays to decimal
        num1 = to_decimal(arr1)
        num2 = to_decimal(arr2)

        # Add the decimal numbers
        total = num1 + num2

        # Convert the sum back to base -2 and return
        return to_base_neg2(total)
