class Solution:
    def findRadius(self, houses: List[int], heaters: List[int]) -> int:
        heaters.sort()
        max_radius = 0
        for house in houses:
            left, right = 0, len(heaters) - 1
            min_dist = float('inf')
            while left <= right:
                mid = (left + right) // 2
                if heaters[mid] < house:
                    left = mid + 1
                else:
                    right = mid - 1
            # left is the first heater >= house
            min_dist = min(min_dist, house - heaters[left-1] if left > 0 else float('inf'))
            min_dist = min(min_dist, heaters[left] - house if left < len(heaters) else float('inf'))
            max_radius = max(max_radius, min_dist)
        return max_radius
