from typing import List

class Solution:
    def numberOfPairs(self, points: List[List[int]]) -> int:
        n = len(points)
        count = 0

        # Iterate over all pairs of points (Alice, Bob)
        for alice in range(n):
            for bob in range(n):
                if alice == bob:
                    continue
                # Check if Alice can be upper left and Bob lower right
                # Alice's x <= Bob's x and Alice's y >= Bob's y
                if points[alice][0] <= points[bob][0] and points[alice][1] >= points[bob][1]:
                    # Check if any other point is inside or on the fence
                    valid = True
                    for p in points:
                        if p == points[alice] or p == points[bob]:
                            continue
                        # Check if p is inside or on the rectangle
                        if (points[alice][0] <= p[0] <= points[bob][0] and 
                            points[bob][1] <= p[1] <= points[alice][1]):
                            valid = False
                            break
                    if valid:
                        count += 1
        return count
