class Solution:
    def encode(self, s: str) -> str:
        n = len(s)
        dp = [["" for _ in range(n)] for _ in range(n)]

        for i in range(n - 1, -1, -1):
            for j in range(i, n):
                if i == j:
                    dp[i][j] = s[i]
                else:
                    # Case 1: no encoding
                    dp[i][j] = s[i:j+1]
                    # Case 2: check all possible splits
                    for k in range(i, j):
                        candidate = dp[i][k] + dp[k+1][j]
                        if len(candidate) < len(dp[i][j]):
                            dp[i][j] = candidate
                    # Case 3: check for repeated patterns
                    for l in range(1, (j - i + 1) // 2 + 1):
                        if (j - i + 1) % l == 0:
                            substr = s[i:i+l]
                            repeat = (j - i + 1) // l
                            if substr * repeat == s[i:j+1]:
                                encoded = f"{repeat}[{dp[i][i + l - 1]}]"
                                if len(encoded) < len(dp[i][j]):
                                    dp[i][j] = encoded
        return dp[0][n-1]
