from typing import List
from collections import defaultdict, deque

class Solution:
    def collectTheCoins(self, coins: List[int], edges: List[List[int]]) -> int:
        n = len(coins)
        if n == 0:
            return 0

        # Build the tree as an adjacency list
        tree = defaultdict(list)
        for u, v in edges:
            tree[u].append(v)
            tree[v].append(u)

        # Step 1: Remove all leaves with no coins and their edges
        # First pass: remove leaves without coins
        def remove_leaves_without_coins():
            degree = [0] * n
            for u in range(n):
                degree[u] = len(tree[u])

            queue = deque()
            for i in range(n):
                if degree[i] == 0:
                    queue.append(i)

            while queue:
                u = queue.popleft()
                for v in tree[u]:
                    if degree[v] > 0:
                        degree[v] -= 1
                        if degree[v] == 0:
                            queue.append(v)
                # Remove u from the tree
                for v in tree[u]:
                    tree[v].remove(u)
                tree[u].clear()

            # After this, we have a pruned tree with only nodes that have coins or are connected to them

        remove_leaves_without_coins()

        # Step 2: Remove leaves that have coins but are not needed
        # Second pass: remove leaves with coins
        def remove_leaves_with_coins():
            degree = [0] * n
            for u in range(n):
                degree[u] = len(tree[u])

            queue = deque()
            for i in range(n):
                if degree[i] == 0:
                    queue.append(i)

            while queue:
                u = queue.popleft()
                for v in tree[u]:
                    if degree[v] > 0:
                        degree[v] -= 1
                        if degree[v] == 0:
                            queue.append(v)
                # Remove u from the tree
                for v in tree[u]:
                    tree[v].remove(u)
                tree[u].clear()

        remove_leaves_with_coins()

        # Step 3: Calculate the total number of edges in the remaining tree
        # This is the answer since we need to traverse each edge twice (go and return)
        # But if the tree is empty, the answer is 0
        total_edges = 0
        for u in range(n):
            total_edges += len(tree[u])

        # Since each edge is counted twice (once from each end), divide by 2
        return total_edges // 2
