class Solution:
    def rectangleArea(self, rectangles: List[List[int]]) -> int:
        MOD = 10**9 + 7
        events = []
        for x1, y1, x2, y2 in rectangles:
            events.append((x1, y1, y2, 1))
            events.append((x2, y1, y2, -1))

        events.sort()
        res = 0
        active = set()
        prev_x = 0
        y_intervals = []

        for x, y1, y2, typ in events:
            if prev_x > 0:
                if active:
                    # Calculate the total covered y interval
                    y_total = 0
                    y_start = None
                    for y in sorted(active):
                        if y_start is None:
                            y_start = y
                        else:
                            y_total += y - y_start
                            y_start = y
                    if y_start is not None:
                        y_total += y2 - y_start
                    res += (x - prev_x) * y_total
                    res %= MOD
            if typ == 1:
                active.add(y1)
            else:
                active.remove(y1)
            prev_x = x

        return res % MOD
