class Solution:
    def singleNumber(self, nums: List[int]) -> int:
        # Initialize result to 0
        result = 0

        # Iterate through each bit position (from 0 to 31)
        for i in range(32):
            # Count the number of elements with the ith bit set
            count = 0
            for num in nums:
                # Handle negative numbers using two's complement
                if (num >> i) & 1:
                    count += 1

            # If the count is not a multiple of 3, the ith bit in the result is set
            if count % 3 != 0:
                # For 32-bit signed integers, if the 31st bit is set, it's a negative number
                if i == 31:
                    # Convert from two's complement to a negative number
                    result -= (1 << 31)
                else:
                    result |= (1 << i)

        return result
