from typing import List
from collections import defaultdict

class Solution:
    def deleteDuplicateFolder(self, paths: List[List[str]]) -> List[List[str]]:
        # Build the trie structure
        trie = defaultdict(dict)
        for path in paths:
            node = trie
            for dir in path:
                node = node[dir]

        # Build the hash map for folder structures
        folder_map = {}
        def dfs(node, path):
            key = tuple(path)
            if key not in folder_map:
                folder_map[key] = []
            folder_map[key].append(path)
            for dir, child in node.items():
                dfs(child, path + [dir])

        dfs(trie, [])

        # Find duplicate folders
        duplicate_paths = set()
        for paths_list in folder_map.values():
            if len(paths_list) >= 2:
                for path in paths_list:
                    duplicate_paths.add(tuple(path))

        # Build the result
        result = []
        visited = set()
        def collect(node, path):
            if tuple(path) in duplicate_paths:
                return
            if tuple(path) in visited:
                return
            visited.add(tuple(path))
            result.append(path)
            for dir, child in node.items():
                collect(child, path + [dir])

        collect(trie, [])

        return result
