class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7

        from collections import defaultdict

        # dp[i][j][last][count] = number of ways to form a sequence with i zeros, j ones, ending with 'last' (0 or 1), with 'count' consecutive same elements
        # We use a dictionary to store the DP state
        dp = [defaultdict(lambda: defaultdict(lambda: 0)) for _ in range(2)]

        # Initialize: we can start with a single 0 or 1
        dp[0][0][0] = 1  # 0 zeros, 0 ones, ending with 0, count of 0s is 1
        dp[0][0][1] = 1  # 0 zeros, 0 ones, ending with 1, count of 1s is 1

        for z in range(zero + 1):
            for o in range(one + 1):
                for last in [0, 1]:
                    for count in range(1, limit + 1):
                        if z == 0 and o == 0:
                            continue
                        # If we end with 'last' and have 'count' of same elements
                        if last == 0:
                            # Try to add a 0
                            if z >= 1:
                                if count < limit:
                                    dp[z][o][0] += dp[z-1][o][0][count] * 1
                                    dp[z][o][0] %= MOD
                                # Try to add a 1 after a 0
                                if o >= 1:
                                    dp[z][o][1] += dp[z][o-1][0][count] * 1
                                    dp[z][o][1] %= MOD
                        else:
                            # Try to add a 1
                            if o >= 1:
                                if count < limit:
                                    dp[z][o][1] += dp[z][o-1][1][count] * 1
                                    dp[z][o][1] %= MOD
                                # Try to add a 0 after a 1
                                if z >= 1:
                                    dp[z][o][0] += dp[z-1][o][1][count] * 1
                                    dp[z][o][0] %= MOD
        # Sum all the ways that use exactly 'zero' zeros and 'one' ones
        result = 0
        for last in [0, 1]:
            result += dp[zero][one][last][count] for count in range(1, limit + 1)
        return result % MOD
